mapper.select:
SELECT
    (SELECT COUNT(*) FROM schedule_project p


             AND p.project_type_code = #{project_type_code}

     ) AS project_total,
    (SELECT COUNT(*) FROM schedule_project p

         AND p.project_status = 'PLANNING'

             AND p.project_type_code = #{project_type_code}

     ) AS project_planning,
    (SELECT COUNT(*) FROM schedule_project p

         AND p.project_status = 'IN_PROGRESS'

             AND p.project_type_code = #{project_type_code}

     ) AS project_in_progress,
    (SELECT COUNT(*) FROM schedule_project p

         AND p.project_status = 'DONE'

             AND p.project_type_code = #{project_type_code}

     ) AS project_done,
    (SELECT COUNT(*) FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id


             AND p.project_type_code = #{project_type_code}

     ) AS task_total,
    (SELECT COUNT(*) FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id

         AND t.task_status = 'TODO'

             AND p.project_type_code = #{project_type_code}

     ) AS task_todo,
    (SELECT COUNT(*) FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id

         AND t.task_status = 'IN_PROGRESS'

             AND p.project_type_code = #{project_type_code}

     ) AS task_in_progress,
    (SELECT COUNT(*) FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id

         AND t.task_status = 'DONE'

             AND p.project_type_code = #{project_type_code}

     ) AS task_done,
    (SELECT COUNT(*) FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id

         AND t.due_date < CURRENT_DATE
         AND t.task_status <> 'DONE'

             AND p.project_type_code = #{project_type_code}

     ) AS overdue_task_count,
    (SELECT COUNT(*) FROM schedule_milestone m INNER JOIN schedule_project p ON p.project_id = m.project_id

         AND m.due_date BETWEEN CURRENT_DATE AND CURRENT_DATE + 30

             AND p.project_type_code = #{project_type_code}

     ) AS upcoming_milestone_count

SELECT p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.owner_user_id, p.start_date AS project_start_date, p.end_date AS project_end_date, COUNT(t.task_id) AS task_count, COUNT(t.task_id) FILTER (WHERE t.task_status = 'DONE') AS done_count, COUNT(t.task_id) FILTER (WHERE t.due_date < CURRENT_DATE AND t.task_status <> 'DONE') AS overdue_count, COALESCE(ROUND(AVG(t.progress_rate)::numeric, 1), 0) AS progress_avg, COALESCE(SUM(t.support_amount), 0) AS support_total, COALESCE(SUM(t.actual_amount), 0) AS actual_total, MIN(t.start_date) AS target_start_date, MAX(t.due_date) AS target_end_date, MIN(t.actual_start_date) AS actual_start_date, MAX(t.actual_end_date) AS actual_end_date, CASE WHEN p.project_type_code = 'BLOG' THEN '지원금' WHEN p.project_type_code = 'DEVELOPMENT' THEN '진행률' ELSE '진행률' END AS main_metric_label, CASE WHEN p.project_type_code = 'BLOG' THEN COALESCE(SUM(t.support_amount), 0) ELSE COALESCE(ROUND(AVG(t.progress_rate)::numeric, 1), 0) END AS main_metric_value, CASE WHEN p.project_type_code = 'BLOG' THEN '사용금액' WHEN p.project_type_code = 'DEVELOPMENT' THEN '완료' ELSE '완료' END AS sub_metric_label, CASE WHEN p.project_type_code = 'BLOG' THEN COALESCE(SUM(t.actual_amount), 0) ELSE COUNT(t.task_id) FILTER (WHERE t.task_status = 'DONE') END AS sub_metric_value FROM schedule_project p LEFT JOIN schedule_task t ON t.project_id = p.project_id
AND p.project_type_code = #{project_type_code}
GROUP BY p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.owner_user_id, p.start_date, p.end_date ORDER BY p.project_type_code, p.project_id DESC

WITH typed_task AS ( SELECT p.project_type_code, CASE WHEN p.project_type_code = 'DEVELOPMENT' THEN COALESCE(t.actual_end_date, t.due_date, t.start_date) ELSE COALESCE(t.due_date, t.start_date) END AS basis_date, t.task_status, t.due_date, t.progress_rate, t.support_amount, t.actual_amount FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id
AND p.project_type_code = #{project_type_code}
) SELECT TO_CHAR(DATE_TRUNC('month', basis_date), 'YYYY-MM') AS month_key, project_type_code, COUNT(*) AS task_count, COUNT(*) FILTER (WHERE task_status = 'DONE') AS done_count, COUNT(*) FILTER (WHERE due_date < CURRENT_DATE AND task_status <> 'DONE') AS overdue_count, COALESCE(ROUND(AVG(progress_rate)::numeric, 1), 0) AS progress_avg, COALESCE(SUM(support_amount), 0) AS support_total, COALESCE(SUM(actual_amount), 0) AS actual_total FROM typed_task WHERE basis_date IS NOT NULL GROUP BY DATE_TRUNC('month', basis_date), project_type_code ORDER BY month_key DESC, project_type_code LIMIT 36
